// Map raw PS4 gamepad data to canonical axis/button names.
// Axes 1 and 3 (left/right stick Y) are inverted on PS4 hardware.

const prev = flow.get('rawAxes') || { boom: 0, stick: 0, bucket: 0, swing: 0 };

// On a tick message with no gamepad data, carry forward previous raw values
const axes = msg.payload.axes || [
  prev.bucket,   // axis 0 = left stick X
  -prev.boom,    // axis 1 = left stick Y (uninvert for storage)
  prev.swing,    // axis 2 = right stick X
  -prev.stick    // axis 3 = right stick Y (uninvert for storage)
];

const buttons = msg.payload.buttons || [];

const mapped = {
  axes: {
    boom:   -(axes[1] || 0),   // invert
    stick:  -(axes[3] || 0),   // invert
    bucket:   axes[0] || 0,
    swing:    axes[2] || 0
  },
  buttons: {
    deadman:     !!(buttons[7] && buttons[7].pressed),
    mode_toggle: !!(buttons[3] && buttons[3].pressed),
    reset:       !!(buttons[9] && buttons[9].pressed)
  },
  raw_connected: msg.payload.axes !== undefined
};

flow.set('rawAxes', mapped.axes);
msg.payload = mapped;
return msg;

// Apply deadzone → rescale → lerp → clamp to each axis.
// Persists previous smoothed values in flow context for lerp continuity.

const DEADZONE = 0.08;
const LERP_ALPHA = 0.15;

function applyDeadzone(value, threshold) {
  if (Math.abs(value) < threshold) return 0.0;
  return value;
}

function rescaleAfterDeadzone(value, threshold) {
  if (value === 0) return 0;
  const sign = value > 0 ? 1 : -1;
  return sign * (Math.abs(value) - threshold) / (1 - threshold);
}

function lerp(current, target, alpha) {
  return current + (target - current) * alpha;
}

function clamp(value, min, max) {
  return Math.max(min, Math.min(max, value));
}

function transformAxis(raw, prev) {
  const dz = applyDeadzone(raw, DEADZONE);
  const rs = rescaleAfterDeadzone(dz, DEADZONE);
  const sm = lerp(prev, rs, LERP_ALPHA);
  return clamp(sm, -1.0, 1.0);
}

const prev = flow.get('prevAxes') || { boom: 0, stick: 0, bucket: 0, swing: 0 };
const raw = msg.payload.axes;

const smoothed = {
  boom:   transformAxis(raw.boom,   prev.boom),
  stick:  transformAxis(raw.stick,  prev.stick),
  bucket: transformAxis(raw.bucket, prev.bucket),
  swing:  transformAxis(raw.swing,  prev.swing)
};

flow.set('prevAxes', smoothed);

// Safety: deadman switch forces all axes to 0
const deadman = msg.payload.buttons.deadman;
const safeAxes = deadman ? smoothed : { boom: 0, stick: 0, bucket: 0, swing: 0 };

msg.payload = {
  timestamp: Date.now(),
  device: 'ps4',
  axes: safeAxes,
  buttons: msg.payload.buttons,
  meta: {
    raw_connected: msg.payload.raw_connected,
    profile: 'ps4'
  }
};

return msg;
